// Idempotency tracking (in production, use Redis or a database)
const processedIdempotencyKeys = new Map();
const IDEMPOTENCY_TTL = 10 * 60 * 1000; // 10 minutes

function isAlreadyProcessed(idempotencyKey) {
  const entry = processedIdempotencyKeys.get(idempotencyKey);
  if (!entry) return false;
  if (Date.now() - entry.timestamp > IDEMPOTENCY_TTL) {
    processedIdempotencyKeys.delete(idempotencyKey);
    return false;
  }
  return true;
}

function markAsProcessed(idempotencyKey) {
  processedIdempotencyKeys.set(idempotencyKey, { timestamp: Date.now() });
}

// Clean up expired idempotency keys periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, entry] of processedIdempotencyKeys.entries()) {
    if (now - entry.timestamp > IDEMPOTENCY_TTL) {
      processedIdempotencyKeys.delete(key);
    }
  }
}, 60000);

